  const [items, setItems] = useState([
    { id: 1, name: 'Item 1' },
    { id: 2, name: 'Item 2' },
    { id: 3, name: 'Item 3' },
  ]);

  useEffect(() => {
    items.forEach((item) => {
      const element = document.getElementById(item.id);
      element.addEventListener('click', () => {
